// ── دوال مساعدة لبناء n8n workflows ──

// هيكل workflow فارغ
const workflow = (name, nodes = [], connections = {}) => ({
  name,
  nodes,
  connections,
  settings: { executionOrder: 'v1' }
});

// node: Schedule Trigger
const scheduleTrigger = (id, cron = '0 9 * * 1-5') => ({
  id, name: 'Schedule Trigger',
  type: 'n8n-nodes-base.scheduleTrigger',
  position: [240, 300], typeVersion: 1.2,
  parameters: { rule: { interval: [{ field: 'cronExpression', expression: cron }] } }
});

// node: HTTP Request
const httpRequest = (id, name, url, method = 'GET') => ({
  id, name,
  type: 'n8n-nodes-base.httpRequest',
  position: [460, 300], typeVersion: 4.2,
  parameters: { url, method, options: {} }
});

// node: Code
const codeNode = (id, name, code) => ({
  id, name,
  type: 'n8n-nodes-base.code',
  position: [680, 300], typeVersion: 2,
  parameters: { jsCode: code }
});

// connection helper
const connect = (from, to) => ({ [from]: { main: [[{ node: to, type: 'main', index: 0 }]] } });

return { workflow, scheduleTrigger, httpRequest, codeNode, connect, message: 'Helpers ready' };
